class User:
    def __init__(self, username, password, mfa_enabled=False, mfa_secret=None):
        self.username = username
        self.password = password  # In production, use hashed passwords (bcrypt, etc.)
        self.mfa_enabled = mfa_enabled
        self.mfa_secret = mfa_secret
        self.api_key = None

    def verify_password(self, password):
        return self.password == password  # In production, use bcrypt.checkpw()

    def verify_otp(self, otp):
        if not self.mfa_secret:
            return False
        totp = pyotp.TOTP(self.mfa_secret)
        return totp.verify(otp, valid_window=1)

    def to_dict(self):
        return {
            'username': self.username,
            'mfa_enabled': self.mfa_enabled,
            'api_key': self.api_key,
        }


def login_required(f):
    """Decorator to require authentication for web routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session or not session.get('authenticated'):
            return redirect(url_for('login'))
        username = session['user']
        if username not in USERS:
            session.clear()
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def api_key_required(f):
    """Decorator to require API key authentication for API routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key') or request.args.get('api_key')
        if not api_key or api_key not in API_KEYS:
            return jsonify({'error': 'Invalid or missing API key'}), 401
        request.api_user = USERS[API_KEYS[api_key]]
        return f(*args, **kwargs)
    return decorated_function


