@app.route('/enable-mfa', methods=['GET', 'POST'])
@login_required
def enable_mfa():
    user = USERS[session['user']]

    if user.mfa_enabled:
        return redirect(url_for('dashboard', message='MFA is already enabled'))

    if request.method == 'GET':
        secret = pyotp.random_base32()
        totp = pyotp.TOTP(secret)
        uri = totp.provisioning_uri(name=user.username, issuer_name='FlaskAuthApp')
        return render_template_string(ENABLE_MFA_TEMPLATE, secret=secret, uri=uri, error=None)

    secret = request.form.get('secret', '').strip()
    otp = request.form.get('otp', '').strip()

    if not secret or not otp:
        totp = pyotp.TOTP(secret)
        uri = totp.provisioning_uri(name=user.username, issuer_name='FlaskAuthApp')
        return render_template_string(ENABLE_MFA_TEMPLATE, secret=secret, uri=uri, error='Please enter the OTP')

    totp = pyotp.TOTP(secret)
    if not totp.verify(otp, valid_window=1):
        uri = totp.provisioning_uri(name=user.username, issuer_name='FlaskAuthApp')
        return render_template_string(ENABLE_MFA_TEMPLATE, secret=secret, uri=uri, error='Invalid OTP. Try again.')

    user.mfa_secret = secret
    user.mfa_enabled = True
    return redirect(url_for('dashboard', message='MFA enabled successfully'))


