@app.route('/generate-api-key')
@login_required
def generate_api_key():
    user = USERS[session['user']]
    # Remove old API key if exists
    if user.api_key and user.api_key in API_KEYS:
        del API_KEYS[user.api_key]
    # Generate new API key
    api_key = secrets.token_hex(32)
    user.api_key = api_key
    API_KEYS[api_key] = user.username
    return redirect(url_for('dashboard', message=f'New API key generated: {api_key}'))


