# ==================== API Routes ====================

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    """
    Direct login endpoint for API clients and automated scripts.
    Skips MFA checks entirely — authenticates with username/password or API key.
    Returns a session token / API key for subsequent requests.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    # Option 1: Authenticate with API key
    api_key = data.get('api_key') or request.headers.get('X-API-Key')
    if api_key:
        if api_key in API_KEYS:
            username = API_KEYS[api_key]
            user = USERS[username]
            return jsonify({
                'success': True,
                'message': 'Authenticated via API key (MFA skipped)',
                'user': user.to_dict(),
                'auth_method': 'api_key',
                'token': api_key,
            }), 200
        else:
            return jsonify({'error': 'Invalid API key'}), 401

    # Option 2: Authenticate with username/password (MFA skipped)
    username = data.get('username', '').strip()
    password = data.get('password', '').strip()

    if not username or not password:
        return jsonify({'error': 'Username and password are required (or provide api_key)'}), 400

    user = USERS.get(username)
    if not user or not user.verify_password(password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Generate API key if user doesn't have one
    if not user.api_key:
        api_key = secrets.token_hex(32)
        user.api_key = api_key
        API_KEYS[api_key] = user.username

    return jsonify({
        'success': True,
        'message': 'Authenticated via direct login (MFA skipped)',
        'user': user.to_dict(),
        'auth_method': 'direct_login',
        'token': user.api_key,
        'mfa_status': 'skipped' if user.mfa_enabled else 'not_configured',
    }), 200


