@app.route('/api/register', methods=['POST'])
def api_register():
    """API endpoint to register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '').strip()
    enable_mfa = data.get('enable_mfa', False)

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    if username in USERS:
        return jsonify({'error': 'Username already exists'}), 409

    if len(password) < 6:
        return jsonify({'error': 'Password must be at least 6 characters'}), 400

    mfa_secret = pyotp.random_base32() if enable_mfa else None
    user = User(username, password, mfa_enabled=enable_mfa, mfa_secret=mfa_secret)

    # Auto-generate API key for API-registered users
    api_key = secrets.token_hex(32)
    user.api_key = api_key
    API_KEYS[api_key] = username
    USERS[username] = user

    response = {
        'success': True,
        'message': 'User registered successfully',
        'user': user.to_dict(),
        'api_key': api_key,
    }

    if enable_mfa:
        totp = pyotp.TOTP(mfa_secret)
        response['mfa_secret'] = mfa_secret
        response['mfa_provisioning_uri'] = totp.provisioning_uri(
            name=username, issuer_name='FlaskAuthApp'
        )

    return jsonify(response), 201


